refentry.refsect1:
  &reftitle.examples;



    memcache_prepend example


<?php
/* procedural API */

/* connect to memcached server */
$memcache_obj = memcache_connect('memcache_host', 11211);

/* store an initial value */
memcache_set($memcache_obj, 'var_key', 'world', 0, 30);

/* prepend data to the beginning of the existing value */
memcache_prepend($memcache_obj, 'var_key', 'hello ');

/* outputs "hello world" */
echo memcache_get($memcache_obj, 'var_key');

?>




    Memcache::prepend example


<?php
/* OO API */

$memcache_obj = new Memcache;

/* connect to memcached server */
$memcache_obj->connect('memcache_host', 11211);

/* store an initial value */
$memcache_obj->set('var_key', 'world', 0, 30);

/* prepend data to the beginning of the existing value */
$memcache_obj->prepend('var_key', 'hello ');

/* outputs "hello world" */
echo $memcache_obj->get('var_key');

?>
